package com.hospital.management.validation;import com.hospital.management.model.*;import org.junit.jupiter.api.Test;import java.time.LocalDate;import java.util.*;import static org.junit.jupiter.api.Assertions.*;class PrescriptionValidatorTest {private final PrescriptionValidator v=new PrescriptionValidator();private PrescriptionForm valid(){PrescriptionForm f=new PrescriptionForm();f.setMedicalRecordId(1L);f.setValidUntil(LocalDate.now().plusDays(30).toString());f.setStatus("ACTIVE");PrescriptionItemForm i=new PrescriptionItemForm();i.setMedicineName("Paracetamol");i.setDosage("500 mg");i.setFrequency("Twice daily");i.setDuration("5 days");f.setItems(List.of(i));return f;}@Test void validHeaderAndItem(){assertFalse(v.validate(valid()).hasErrors());}@Test void missingMedicalRecord(){PrescriptionForm f=valid();f.setMedicalRecordId(null);assertNotNull(v.validate(f).getError("medicalRecordId"));}@Test void noItems(){PrescriptionForm f=valid();f.setItems(List.of());assertNotNull(v.validate(f).getError("items"));}@Test void tooManyItems(){PrescriptionForm f=valid();f.setItems(Collections.nCopies(21,f.getItems().get(0)));assertNotNull(v.validate(f).getError("items"));}@Test void invalidDate(){PrescriptionForm f=valid();f.setValidUntil("bad");assertNotNull(v.validate(f).getError("validUntil"));}@Test void blankRequiredItemFields(){PrescriptionForm f=valid();PrescriptionItemForm i=f.getItems().get(0);i.setMedicineName("");i.setDosage("");i.setFrequency("");i.setDuration("");assertTrue(v.validate(f).getErrors().size()>=4);}@Test void longInstructions(){PrescriptionForm f=valid();f.getItems().get(0).setInstructions("x".repeat(501));assertNotNull(v.validate(f).getError("items[0].instructions"));}@Test void invalidStatus(){PrescriptionForm f=valid();f.setStatus("UNKNOWN");assertNotNull(v.validate(f).getError("status"));}}
